#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAX 100

void dijkstra(int graph[MAX][MAX], int vertices, int start, int target) {
  int dist[MAX];
  int visited[MAX] = {0};
  for (int i = 0; i < vertices; i++) {
    dist[i] = INT_MAX;
  }
  dist[start] = 0;
  for (int count = 0; count < vertices - 1; count++) {
    int min = INT_MAX, u;
    for (int i = 0; i < vertices; i++) {
      if (!visited[i] && dist[i] <= min) {
        min = dist[i];
        u = i;
      }
    }
    visited[u] = 1;
    for (int v = 0; v < vertices; v++) {
      if (!visited[v] && graph[u][v] && dist[u] != INT_MAX && dist[u] + graph[u][v] < dist[v]) {
        dist[v] = dist[u] + graph[u][v];
      }
    }
  }
  if (dist[target] == INT_MAX) {
    printf("Target not reachable\n");
  } else {
    printf("Distance to target: %d\n", dist[target]);
  }
}

int main() {
  int vertices = 5;
  int graph[MAX][MAX] = {
    {0, 4, 2, 0, 0},
    {4, 0, 5, 10, 0},
    {2, 5, 0, 3, 8},
    {0, 10, 3, 0, 6},
    {0, 0, 8, 6, 0}
  };
  dijkstra(graph, vertices, 0, 4);
  return 0;
}
// Output: Distance to target: 8

